  ('dfbcef8f-9a4a-494c-8e86-fba907fe6612', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, '¿Qué diferencia hay entre anabolismo y catabolismo, ambos parte del metabolismo?', '["El anabolismo construye moléculas complejas; el catabolismo las descompone, liberando energía", "Son exactamente lo mismo", "El catabolismo solo ocurre en plantas", "El anabolismo detiene toda actividad celular"]'::jsonb, '0', '2026-07-19 03:06:31.505151+00', NULL, 'El anabolismo construye moléculas (gasta energía); el catabolismo las descompone (libera energía).', '4588bf8a-dd5c-4fa8-a13a-aba70b122507', NULL, 'intermedia', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:31.505151+00', 'ai_generated_review_required', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, '84c615ca7563251722b7beacf41556ab75c32d27b9059885aff801fe22f05067', NULL, '{}'::uuid[], '2026-07-19 03:06:31.505151+00', 'claude-sonnet-5'),
