  ('5fb7868e-cd1f-41e7-9d86-8456a85f03bc', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, '¿Qué función cumple el hígado en el proceso de nutrición?', '["Participa en la producción de bilis, que ayuda a digerir las grasas", "Bombea la sangre por el cuerpo", "Produce el aire que respiramos", "Almacena únicamente agua"]'::jsonb, '0', '2026-07-19 03:06:32.14961+00', NULL, 'El hígado produce bilis, sustancia que ayuda a digerir las grasas en el intestino.', 'ced8645c-d125-4a6e-a56f-aa642534833d', NULL, 'avanzada', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:32.14961+00', 'ai_generated_review_required', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, 'f1947d36719441fe243f6fb68d238519933333d811cdee7a15d8ded10c082a4f', NULL, '{}'::uuid[], '2026-07-19 03:06:32.14961+00', 'claude-sonnet-5'),
  ('70748a89-49e4-4a93-aefb-edc4456364d2', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, '¿Qué se entiende por biodiversidad?', '["La variedad de especies de seres vivos que existen en un ecosistema o en el planeta", "La cantidad de agua disponible en un lugar", "El número de ríos de un país", "La temperatura promedio de una región"]'::jsonb, '0', '2026-07-19 03:06:32.365575+00', NULL, 'La biodiversidad se refiere a la variedad de especies vivas presentes en un ecosistema o planeta.', '60cedbcf-5b66-40b7-92f7-7608278e55d3', NULL, 'intermedia', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:32.365575+00', 'ai_generated_review_required', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, '0a3727798defd51703c1f8b78c8d4f337a65cd8811559a53e57f6d242b1159c8', NULL, '{}'::uuid[], '2026-07-19 03:06:32.365575+00', 'claude-sonnet-5'),
  ('91b6b626-bce9-448c-9692-90fc024f6b1e', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, '¿Qué es una relación de simbiosis en ecología?', '["Una interacción cercana y duradera entre dos especies distintas, que puede beneficiar a una o a ambas", "La competencia total entre dos especies iguales", "La extinción de una especie", "La ausencia de cualquier interacción entre especies"]'::jsonb, '0', '2026-07-19 03:06:32.580099+00', NULL, 'La simbiosis es una relación cercana y sostenida entre especies distintas, con distintos tipos de beneficio.', '34f700ac-9dd2-4457-b1c1-6afb90454110', NULL, 'avanzada', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:32.580099+00', 'ai_generated_review_required', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, '27489101563e43896c526b8df910df198bd824754d04e33d9e67e070068852f8', NULL, '{}'::uuid[], '2026-07-19 03:06:32.580099+00', 'claude-sonnet-5'),
  ('43687463-fc91-4328-8344-857df5be3246', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, '¿Cuál de las siguientes es una medida efectiva para la conservación del medioambiente?', '["La creación de áreas silvestres protegidas", "El aumento de la contaminación industrial sin control", "La eliminación de todas las especies depredadoras", "La tala indiscriminada de bosques"]'::jsonb, '0', '2026-07-19 03:06:32.7951+00', NULL, 'Las áreas silvestres protegidas son una medida reconocida de conservación ambiental.', '9a892217-9476-41e7-8613-1bf29dc7f655', NULL, 'intermedia', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:32.7951+00', 'automatically_validated', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, 'b94b89a448ce7dd15487120a3fdc2489366f8966e369ad57143838f267ca01e6', NULL, '{}'::uuid[], '2026-07-19 03:06:32.7951+00', 'claude-sonnet-5'),
  ('3372d936-8a44-4676-b158-12afe14891c2', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, 'En un movimiento circular uniforme, ¿qué característica se mantiene constante?', '["La rapidez (magnitud de la velocidad)", "La dirección del movimiento", "La posición del objeto", "La aceleración es siempre cero"]'::jsonb, '0', '2026-07-19 03:06:33.010096+00', NULL, 'En el movimiento circular uniforme la rapidez es constante, aunque la dirección cambia continuamente.', 'ceb92b91-b848-4fb7-8d17-a9bc1b119a56', NULL, 'avanzada', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:33.010096+00', 'automatically_validated', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, '3c4eed9201d496b8f053de89e47eb544da7abef8a4e352ad9160a4e31f573c3c', NULL, '{}'::uuid[], '2026-07-19 03:06:33.010096+00', 'claude-sonnet-5'),
  ('3ab129e7-ed9b-49d2-8543-934e1d1d4836', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, 'Según la segunda ley de Newton, la aceleración de un objeto es:', '["Directamente proporcional a la fuerza neta aplicada e inversamente proporcional a su masa", "Siempre constante sin importar la fuerza aplicada", "Independiente de la masa del objeto", "Siempre igual a cero"]'::jsonb, '0', '2026-07-19 03:06:33.225598+00', NULL, 'La segunda ley de Newton establece que a = F/m: la aceleración depende de la fuerza aplicada y la masa.', '30e05550-3ae3-4a2b-aafe-ac1eeb229599', NULL, 'avanzada', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:33.225598+00', 'ai_generated_review_required', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, '04a038eb268990ace05a920701c719721a41a049160df056c080c73ddf6e808a', NULL, '{}'::uuid[], '2026-07-19 03:06:33.225598+00', 'claude-sonnet-5'),
  ('f378113a-36c3-45c7-a4af-8948347055f6', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, '¿Qué diferencia hay entre una onda longitudinal y una onda transversal?', '["En la longitudinal, la vibración es paralela a la dirección de propagación; en la transversal, es perpendicular", "Son exactamente el mismo tipo de onda", "La longitudinal solo existe en el vacío", "La transversal no puede transportar energía"]'::jsonb, '0', '2026-07-19 03:06:33.441123+00', NULL, 'En ondas longitudinales la vibración es paralela a la propagación (como el sonido); en las transversales, perpendicular (como la luz).', 'cccada4c-ea1f-40ec-b38a-f548a488dada', NULL, 'avanzada', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:33.441123+00', 'ai_generated_review_required', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, '5b556cd30d8b4f6faf5c0cab8e47465a9efda35d1a09c264651fc1467bb10318', NULL, '{}'::uuid[], '2026-07-19 03:06:33.441123+00', 'claude-sonnet-5'),
  ('81618072-780d-45bd-ac84-e9fa118fe502', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, '¿Qué es el roce o fricción, en términos físicos?', '["Una fuerza que se opone al movimiento relativo entre dos superficies en contacto", "Una forma de energía eléctrica", "Un tipo de onda sonora", "Un cambio de estado de la materia"]'::jsonb, '0', '2026-07-19 03:06:33.656568+00', NULL, 'El roce es una fuerza que se opone al deslizamiento entre superficies en contacto.', '1973638f-b701-445a-b0e7-dcb424a9d557', NULL, 'intermedia', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:33.656568+00', 'ai_generated_review_required', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, '8bfdcb824525a37857b70ee95beb7c530b847a15952e10c592b01f4fcb427010', NULL, '{}'::uuid[], '2026-07-19 03:06:33.656568+00', 'claude-sonnet-5'),
  ('dd779f19-80be-41f4-8708-02bca836115f', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, '¿Qué característica del sonido determina su volumen (qué tan fuerte se escucha)?', '["La amplitud de la onda sonora", "El color de la fuente sonora", "La temperatura del aire únicamente", "El tamaño del objeto que la produce"]'::jsonb, '0', '2026-07-19 03:06:33.872138+00', NULL, 'La amplitud de la onda sonora determina su volumen o intensidad.', '93661fee-08a1-4eb6-a41f-f821d833ea1c', NULL, 'intermedia', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:33.872138+00', 'automatically_validated', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, '86188acef7b3f1a38e8c91d6c7f5a011a9b46570b2a13eb8214d966c9b391e15', NULL, '{}'::uuid[], '2026-07-19 03:06:33.872138+00', 'claude-sonnet-5'),
  ('fd9eff4d-5e8f-4c19-a591-a8aad88c3ed8', '9e370682-12df-4ea6-89e6-9aa124f540a3', 'cb7467bf-5407-40f6-953e-28ad17aae434', NULL, 'En una colisión donde no actúan fuerzas externas, ¿qué cantidad física se conserva, según el principio de conservación del momentum?', '["El momentum (cantidad de movimiento) total del sistema", "La temperatura del sistema", "El color de los objetos", "El volumen de los objetos"]'::jsonb, '0', '2026-07-19 03:06:34.086898+00', NULL, 'El principio de conservación del momentum indica que, sin fuerzas externas, el momentum total del sistema se mantiene constante.', '175e7ded-10f6-4091-bbbc-d8c5034c251f', NULL, 'avanzada', 'seleccion_multiple', '1', NULL, NULL, 'en_revision', '2026-07-19 03:06:34.086898+00', 'ai_generated_review_required', 'true', 'b83f2d84-f278-4f26-af9d-317667f5d300', NULL, 'validapp_original', NULL, NULL::jsonb, NULL::jsonb, '5b87485e299bd7889859817f1c6cde3ab75ef897996bea8edff231b6cc90a72c', NULL, '{}'::uuid[], '2026-07-19 03:06:34.086898+00', 'claude-sonnet-5'),
